import time
from functools import lru_cache

# --- Fallback 1: secondary provider ---
def search_web(query: str, limit: int = 5) -> dict[str, Any]:
    # Try Brave first
    try:
        result = _search_brave(query, limit)
        if "error" not in result:
            return result
    except Exception:
        pass
    # Fallback to Serper
    try:
        result = _search_serper(query, limit)
        if "error" not in result:
            return {**result, "provider": "serper", "degraded": True}
    except Exception:
        pass
    return {"error": "SERVICE_UNAVAILABLE",
            "message": "All search providers are unavailable"}

# --- Fallback 2: cached result ---
_PRICE_CACHE: dict[str, tuple[dict, float]] = {}   # product_id -> (result, ts)
_CACHE_TTL = 300   # 5 minutes

def get_product_price(product_id: str) -> dict[str, Any]:
    resp = _SESSION.get(f"{_BASE}/products/{product_id}/price", timeout=8)
    if resp.ok:
        result = {"product_id": product_id, "price_cents": resp.json()["price"]}
        _PRICE_CACHE[product_id] = (result, time.monotonic())
        return result

    # Fallback: return cached price with staleness warning
    cached, ts = _PRICE_CACHE.get(product_id, (None, 0))
    if cached and time.monotonic() - ts < _CACHE_TTL:
        return {**cached, "cached": True, "stale_seconds": int(time.monotonic() - ts)}

    return {"error": "SERVICE_UNAVAILABLE",
            "message": "Pricing service is unavailable and no cached price is available"}

# --- Fallback 3: graceful degradation ---
def get_customer_with_fallback(customer_id: str) -> dict[str, Any]:
    # Try full record
    resp = _SESSION.get(f"{_BASE}/customers/{customer_id}", timeout=8)
    if resp.ok:
        c = resp.json()
        return {"customer_id": c["id"], "name": c["name"], "email": c["email"],
                "tier": c["tier"], "full_record": True}

    # Fallback: try lightweight endpoint that is more reliable
    resp2 = _SESSION.get(f"{_BASE}/customers/{customer_id}/basic", timeout=5)
    if resp2.ok:
        b = resp2.json()
        return {"customer_id": b["id"], "name": b["name"],
                "full_record": False,
                "message": "Returned basic record only; full CRM is temporarily unavailable"}

    return {"error": "SERVICE_UNAVAILABLE",
            "message": "Customer service is unavailable"}

import time
from dataclasses import dataclass, field
from threading import Lock

@dataclass
class CircuitBreaker:
    max_failures: int = 5
    cooldown_seconds: float = 30.0
    _failures: int = field(default=0, init=False, repr=False)
    _opened_at: float | None = field(default=None, init=False, repr=False)
    _lock: Lock = field(default_factory=Lock, init=False, repr=False)

    def is_open(self) -> bool:
        with self._lock:
            if self._opened_at is None:
                return False
            if time.monotonic() - self._opened_at >= self.cooldown_seconds:
                # Half-open: allow one probe
                self._opened_at = None
                self._failures = 0
                return False
            return True

    def record_success(self) -> None:
        with self._lock:
            self._failures = 0
            self._opened_at = None

    def record_failure(self) -> None:
        with self._lock:
            self._failures += 1
            if self._failures >= self.max_failures:
                self._opened_at = time.monotonic()

_breaker: dict[str, CircuitBreaker] = {}

def get_breaker(service: str) -> CircuitBreaker:
    if service not in _breaker:
        _breaker[service] = CircuitBreaker()
    return _breaker[service]

def call_with_circuit_breaker(service: str, fn, *args, **kwargs):
    cb = get_breaker(service)
    if cb.is_open():
        return {
            "error": "SERVICE_UNAVAILABLE",
            "message": f"{service} circuit is open — retrying too soon",
            "retry_after_seconds": cb.cooldown_seconds,
        }
    try:
        result = fn(*args, **kwargs)
        cb.record_success()
        return result
    except Exception as exc:
        cb.record_failure()
        raise

from __future__ import annotations
import random, time
from typing import Any

RETRYABLE_STATUS = {429, 500, 502, 503, 504}
MAX_ATTEMPTS = 3
BASE_DELAY = 1.0

def _backoff(attempt: int) -> float:
    delay = min(BASE_DELAY * 2**attempt, 30.0)
    return delay + random.uniform(0, delay * 0.25)

def call_inventory_api(product_id: str) -> dict[str, Any]:
    """Fetch live inventory; falls back to cached data."""
    import requests
    SERVICE = "inventory"
    cb = get_breaker(SERVICE)

    if not cb.is_open():
        for attempt in range(MAX_ATTEMPTS):
            try:
                r = requests.get(
                    f"https://inventory.internal/products/{product_id}",
                    timeout=5,
                )
                if r.status_code == 200:
                    cb.record_success()
                    return {"source": "live", **r.json()}
                if r.status_code not in RETRYABLE_STATUS:
                    cb.record_success()
                    return {
                        "error": "NOT_FOUND" if r.status_code == 404 else "REQUEST_ERROR",
                        "message": r.text,
                    }
                cb.record_failure()
            except (requests.Timeout, requests.ConnectionError):
                cb.record_failure()

            if attempt < MAX_ATTEMPTS - 1:
                time.sleep(_backoff(attempt))

    # Circuit open or all retries exhausted — activate fallback
    cached = _inventory_cache.get(product_id)
    if cached:
        return {"source": "cache", "stale_seconds": time.time() - cached["ts"], **cached["data"]}
    return {
        "error": "SERVICE_UNAVAILABLE",
        "message": "Inventory service is unavailable and no cached data exists",
        "retry_after_seconds": 30,
    }

_inventory_cache: dict[str, dict] = {}

import time

def remaining(deadline: float) -> float:
    """Seconds left before the agent-level deadline."""
    return max(0.0, deadline - time.monotonic())

def search_and_summarize(query: str, timeout: float = 20.0) -> dict:
    deadline = time.monotonic() + timeout

    budget = remaining(deadline)
    if budget < 2:
        return {"error": "TIMEOUT", "message": "No time left before search step"}

    search_result = call_with_circuit_breaker(
        "search",
        _search,
        query,
        timeout=min(budget * 0.5, 8.0),   # use at most half the budget
    )
    if "error" in search_result:
        return search_result

    budget = remaining(deadline)
    if budget < 2:
        return {"error": "TIMEOUT", "message": "No time left before summarise step"}

    return _summarise(search_result["hits"], timeout=min(budget - 1, 10.0))

def _search(query: str, timeout: float) -> dict:
    import requests
    r = requests.get("https://search.internal/", params={"q": query}, timeout=timeout)
    r.raise_for_status()
    return r.json()

def _summarise(hits: list[dict], timeout: float) -> dict:
    # Call a summarisation model or further processing
    return {"summary": f"Summarised {len(hits)} results", "source": "live"}
